INSERT INTO Product(product_type, product_description) VALUES ('Camera', 'This policy covers accidental damage, liquid damage, fire, and theft of the insured camera. Coverage includes damage resulting from drops, spills, and electrical surges. Theft is covered if the camera was stored securely. Normal wear and tear, careless handling, unauthorized modifications, and mechanical breakdowns not caused by an insured event are excluded.');
INSERT INTO Product(product_type, product_description) VALUES ('Game Console', 'The insured game console is protected against accidental damage, liquid damage, fire, and theft. Coverage includes electrical faults due to power surges, damage from drops, and liquid spills. Theft is covered when reasonable security measures were in place. Exclusions include wear and tear, overheating due to improper use, and damage from unauthorized repairs or modifications.');
INSERT INTO Product(product_type, product_description) VALUES ('Headphones', 'Insurance coverage applies to accidental damage, fire, liquid damage, and theft. Covered incidents include broken ear cups, water exposure, and electrical faults. Loss due to misplacement, general wear and tear, or damage caused by improper storage is not covered.');
INSERT INTO Product(product_type, product_description) VALUES ('Keyboard', 'This policy covers accidental damage, fire, liquid damage, and theft of the insured keyboard. Protection includes damage from spills, drops, or electrical surges. Exclusions include worn-out keys, general deterioration over time, and damage caused by misuse or failure to follow manufacturer guidelines.');
INSERT INTO Product(product_type, product_description) VALUES ('Laptop', 'The insured laptop is covered against accidental damage, fire, liquid damage, and theft. Covered incidents include screen cracks, motherboard failure due to power surges, and water spills. Theft is covered if the device was securely stored. Damage due to improper use, software malfunctions, battery degradation, and normal wear and tear are not covered.');
INSERT INTO Product(product_type, product_description) VALUES ('Mobile Phone', 'This policy provides coverage for accidental damage, liquid damage, fire, and theft. Covered incidents include screen breaks, exposure to water, and electrical failures. Theft is included if reasonable security measures were taken. Exclusions include software corruption, normal battery wear, unauthorized repairs, and negligence leading to loss or damage.');
INSERT INTO Product(product_type, product_description) VALUES ('Monitor', 'Insurance covers accidental damage, liquid damage, fire, and theft. Covered incidents include cracked screens, power surge damage, and exposure to water. Wear and tear, dead pixels from prolonged use, and failure due to improper handling are not covered.');
INSERT INTO Product(product_type, product_description) VALUES ('Mouse', 'This policy includes coverage for accidental damage, fire, and theft. Damage from drops, spills, and electrical faults is covered. Exclusions apply to general wear, loss of responsiveness due to prolonged use, and damage caused by unauthorized repairs.');
INSERT INTO Product(product_type, product_description) VALUES ('Printer', 'The insured printer is covered for accidental damage, fire, liquid damage, and theft. Coverage includes electrical failure from power surges, fire damage, and accidental spills. Exclusions include ink cartridge issues, general wear, and mechanical failures due to improper maintenance.');
INSERT INTO Product(product_type, product_description) VALUES ('Projector', 'This policy covers accidental damage, liquid damage, fire, and theft. Coverage includes broken lenses, liquid spills, and power surge-related failures. Exclusions include bulb replacement due to regular use, dust-related issues, and damage from incorrect installation.');
INSERT INTO Product(product_type, product_description) VALUES ('Router', 'Coverage applies to accidental damage, fire, and theft. Covered incidents include electrical damage from surges and liquid spills. General wear, outdated hardware, and damage from unauthorized modifications are excluded.');
INSERT INTO Product(product_type, product_description) VALUES ('Scanner', 'The insured scanner is covered against accidental damage, fire, and theft. Coverage includes electronic failure due to power surges, damage from accidental spills, and fire-related loss. Mechanical breakdowns due to long-term use, dust accumulation, and failure due to improper maintenance are excluded.');
INSERT INTO Product(product_type, product_description) VALUES ('Smartwatch', 'This policy covers accidental damage, fire, liquid damage, and theft. Protection includes screen cracks, water exposure, and electrical failure. Exclusions apply to battery depletion over time, strap deterioration, and damage due to misuse.');
INSERT INTO Product(product_type, product_description) VALUES ('Speaker', 'The insured speaker is covered against accidental damage, fire, liquid damage, and theft. Coverage includes internal component failure from power surges, water damage, and accidental drops. Damage caused by excessive volume usage, wear from long-term use, and battery degradation is excluded.');
INSERT INTO Product(product_type, product_description) VALUES ('Tablet', 'This policy covers accidental damage, fire, liquid damage, and theft. Covered incidents include cracked screens, power failures, and water exposure. Wear and tear, software issues, and damage due to unauthorized repairs are excluded.');
INSERT INTO Product(product_type, product_description) VALUES ('Television', 'Insurance covers accidental damage, liquid damage, fire, and theft. Protection includes screen cracks, power surges, and fire damage. Exclusions include burn-in from prolonged use, wear and tear, and damage from improper wall mounting.');
INSERT INTO Product(product_type, product_description) VALUES ('Webcam', 'This policy covers accidental damage, fire, liquid damage, and theft. Covered incidents include electrical failures, cracked lenses, and exposure to liquid. Wear over time, lens degradation, and failure due to misuse are excluded.');